async function loadProducts(filter = 'Todos') {
    const productGrid = document.getElementById('product-grid');
    if (!productGrid) return;

    try {
        // Fetching from the local JSON generated by the scraper
        const response = await fetch('data/productos.json');
        const products = await response.json();

        if (products && products.length > 0) {
            productGrid.innerHTML = '';

            // Apply Category Filter
            const filteredProducts = filter === 'Todos'
                ? products
                : products.filter(p => p.category === filter);

            if (filteredProducts.length === 0) {
                productGrid.innerHTML = '<div class="col-span-full text-center text-on-surface-variant py-10">No hay productos en esta categoría.</div>';
                return;
            }

            filteredProducts.forEach(product => {
                const originalPrice = "$" + parseFloat(product.original_price).toFixed(2);
                const finalPrice = "$" + parseFloat(product.price_with_margin).toFixed(2);
                const phone = "595973232127";

                // Dynamic WhatsApp message
                const message = encodeURIComponent(`Hola, vi en la página el producto ${product.name} por ${finalPrice} y me interesa`);
                const waLink = `https://wa.me/${phone}?text=${message}`;

                const card = document.createElement('div');
                card.className = 'glass-panel p-4 rounded-xl flex flex-col justify-between border-t border-white/5 hover:-translate-y-2 transition-transform duration-300';
                card.innerHTML = `
                    <div class="flex flex-col h-full">
                        <div class="w-full h-48 bg-white/5 rounded-lg mb-4 overflow-hidden flex items-center justify-center">
                            <img src="${product.image}" alt="${product.name}" class="w-full h-full object-cover" onerror="this.src='https://via.placeholder.com/300'">
                        </div>
                        <div class="flex-grow">
                            <h4 class="font-headline-md text-on-surface text-lg mb-2 line-clamp-2">${product.name}</h4>
                            <p class="text-on-surface-variant text-xs mb-4 italic">${product.specs}</p>
                        </div>
                        <div class="mt-4">
                            <p class="text-on-surface-variant text-sm line-through">${originalPrice}</p>
                            <p class="text-primary-container font-bold text-xl mb-4">${finalPrice}</p>
                            <a href="${waLink}" target="_blank" class="btn-primary w-full py-2.5 rounded-lg font-label-md flex justify-center items-center gap-2 neon-glow hover:neon-glow-hover">
                                <span class="material-symbols-outlined text-[18px]">shopping_cart</span>
                                Comprar
                            </a>
                        </div>
                    </div>
                `;
                productGrid.appendChild(card);
            });
        } else {
            productGrid.innerHTML = '<div class="col-span-full text-center text-on-surface-variant py-10">No hay productos disponibles en este momento.</div>';
        }
    } catch (error) {
        console.error("Error loading products:", error);
        productGrid.innerHTML = '<div class="col-span-full text-center text-error py-10">Error al cargar la tienda. Intente nuevamente más tarde.</div>';
    }
}

// Initialize products on page load
document.addEventListener('DOMContentLoaded', () => {
    loadProducts();

    // Setup Filter Buttons
    const filterButtons = document.querySelectorAll('.filter-btn');
    filterButtons.forEach(btn => {
        btn.addEventListener('click', (e) => {
            // UI: Update active state
            filterButtons.forEach(b => b.classList.remove('bg-primary-container', 'text-white'));
            btn.classList.add('bg-primary-container', 'text-white');

            const category = btn.getAttribute('data-category');
            loadProducts(category);
        });
    });
});
